export const 入山符五 = (bi) => {
    const u = bi.u;
    const 線 = (書, 寬 = 0.45) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    // 梯箱：凹欄雙立＋橫桁（首末桁即箱之上下緣——四庫本梯箱上下皆直桁）
    const 梯 = (x0, x1, z0, z1, 桁) => {
        const 凹 = 0.5;
        線(p => p.M(x0, z0 - 0.25).C(x0 - 凹, z0 + (z1 - z0) * 0.3, x0 - 凹, z1 - (z1 - z0) * 0.3, x0, z1 + 0.25));
        線(p => p.M(x1, z0 - 0.25).C(x1 + 凹, z0 + (z1 - z0) * 0.3, x1 + 凹, z1 - (z1 - z0) * 0.3, x1, z1 + 0.25));
        // 桁延 ±0.45：內桁必及凹欄最凹處（凹量 0.375，Codex 審 2026-07-12）；
        // 首末桁微出欄外，正合四庫本桁端出頭之貌。
        for (const z of [z0, ...桁, z1])
            線(p => p.M(x0 - 0.45, z).L(x1 + 0.45, z));
    };
    bi.硃(() => {
        // ── 左柱 ──
        // 蛇冠二折
        線(p => p.M(-7.2, 2.9)
            .C(-5.0, 3.6, -1.0, 3.7, 3.6, 3.5)
            .C(5.0, 3.5, 5.5, 4.4, 4.7, 5.1) // 右折
            .C(2.5, 5.8, -3.5, 5.6, -5.6, 5.8)
            .C(-6.7, 5.9, -7.0, 6.7, -6.3, 7.4) // 左折
            .C(-4.5, 7.9, -2.0, 7.8, 0.3, 7.7));
        // 用箱：雙豎＋二桁＋右豎下延成乚鉤
        線(p => p.M(-6.0, 8.6).L(-6.1, 13.6));
        線(p => p.M(0.4, 7.8).L(0.4, 13.2).C(0.4, 14.2, 0.9, 14.7, 1.7, 14.6));
        線(p => p.M(-6.0, 9.0).L(0.4, 8.9));
        線(p => p.M(-6.1, 10.6).L(0.5, 10.5));
        線(p => p.M(-6.1, 12.2).L(0.5, 12.1));
        線(p => p.M(-2.9, 8.9).L(-2.9, 12.2)); // 箱中豎
        // 巴鉤：橫入右折而下，左回長鉤
        線(p => p.M(-5.8, 15.9).L(-0.3, 15.7)
            .C(0.3, 15.7, 0.5, 16.1, 0.5, 16.7)
            .L(0.4, 17.9)
            .C(0.3, 18.7, -0.5, 19.1, -1.9, 19.0)
            .C(-3.4, 18.9, -4.4, 18.4, -4.7, 17.7));
        // 田箱（小梯）＋中莖下貫
        梯(-4.9, -0.6, 20.3, 23.6, [21.9]);
        線(p => p.M(-2.75, 20.3).L(-2.8, 23.5));
        // 波尾
        線(p => p.M(-2.8, 23.6)
            .C(-3.5, 26.2, -2.5, 28.6, -3.3, 31.2)
            .C(-3.6, 32.3, -3.3, 33.3, -2.5, 33.9));
        // ── 右柱 ──
        梯(2.7, 7.5, 4.6, 8.2, [5.8, 7.0]);
        梯(2.6, 7.6, 9.4, 13.2, [10.7, 12.0]);
        梯(2.7, 7.5, 14.4, 18.2, [15.7, 17.0]);
        // 兄形：小梯承雙足
        梯(3.0, 7.2, 19.6, 22.8, [21.2]);
        線(p => p.M(3.7, 23.0)
            .C(3.2, 25.5, 2.6, 27.5, 1.8, 29.3));
        線(p => p.M(6.4, 23.0)
            .C(6.9, 25.5, 6.5, 27.0, 7.3, 28.8)
            .C(7.9, 30.1, 7.7, 31.3, 6.7, 32.2)
            .C(6.2, 32.6, 5.8, 32.6, 5.5, 32.3));
    });
};
